3_real_world_example.code:
// Clean, flat promise chain (Solves Callback Hell)
fetch('/api/user/alice')
  .then(response => {
    return response.json(); // Returns a Promise! Next .then waits for it.
  })
  .then(user => {
    console.log('User ID is:', user.id);
    return fetch(`/api/posts?userId=${user.id}`); // Returns another Promise!
  })
  .then(response => {
    return response.json();
  })
  .then(posts => {
    console.log('User posts:', posts);
  })
  .catch(error => {
    console.error('Failed at some point in the chain:', error);
  });

