Promise.resolve(10)
  .then(val => {
    if (val === 10) throw new Error('Bad number');
    return val * 2;
  })
  .then(val => console.log('This is skipped!'))
  .catch(err => console.log('Caught:', err.message)); // 'Caught: Bad number'
